refsection.programlisting:
image = rgb2gray(imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg")));
image = imresize(image, [90 120]);

weights = 1 + 4 * im2double(image);
seed = [round(size(image, 2) / 2) round(size(image, 1) / 2)];
distance = imgraydist(weights, seed, 8);

seedMask = zeros(size(image, 1), size(image, 2)) == 1;
seedMask(seed(2), seed(1)) = %t;

subplot(1, 3, 1);
imshow(image);
title("Input");
subplot(1, 3, 2);
imshow(imoverlaymask(image, seedMask, [255 0 0], 0.8, %t));
title("Seed");
subplot(1, 3, 3);
imshow(immat2gray(distance));
title("Gray-weighted distance");
